sql:
SELECT complex_name, biological_role
FROM complexes
WHERE integrin = 1 AND biological_role = 'Neuronal cell adhesion';

external_knowledge:
- "Biological complexes" are groups of proteins or other molecules that work together in a cell;
- "Transmembrane proteins" are proteins that span the cell membrane and are often involved in signaling;
- "Secreted" complexes are those that are released outside the cell;
- "Approved comments" are comments that have been reviewed and accepted for display.

