sql:
SELECT complex_name AS receptor_name, biological_role
FROM complexes
WHERE receptor = 1 AND transmembrane = 1 AND peripheral = 0;

SELECT complex_name, biological_role
FROM complexes
WHERE secreted_highlight = 1 AND receptor = 1;

external_knowledge:
